// services/apiUtils.ts

export class ApiServiceError extends Error {
  constructor(message: string, public status?: number) {
    super(message);
    this.name = 'ApiServiceError';
    // This is necessary for correctly extending built-in classes like Error in some environments
    Object.setPrototypeOf(this, ApiServiceError.prototype);
  }
}

/**
 * A utility function that wraps an API call with a retry mechanism.
 * It retries on rate limits (429), server errors (5xx), and network failures.
 * @param apiCall The async function to call.
 * @param maxRetries Maximum number of retries.
 * @param baseDelay Initial delay in milliseconds.
 * @returns The result of the API call.
 */
export const withRetries = async <T>(apiCall: () => Promise<T>, maxRetries = 3, baseDelay = 1000): Promise<T> => {
    let delay = baseDelay;

    for (let i = 0; i < maxRetries; i++) {
        try {
            return await apiCall();
        } catch (error: any) {
            const status = error.status || error.response?.status;
            const errorMessage = error.toString().toLowerCase();

            // Retry on:
            // 1. Rate Limits (429)
            // 2. Resource Exhausted (Gemini specific)
            // 3. Server Errors (500-599)
            // 4. Fetch failures (network blips)
            const isRetryable = 
                errorMessage.includes('429') || 
                errorMessage.includes('resource_exhausted') || 
                errorMessage.includes('rate limit') ||
                errorMessage.includes('fetch failed') || 
                errorMessage.includes('network error') ||
                (status && status >= 500 && status < 600);

            if (isRetryable && i < maxRetries - 1) {
                console.warn(`API Error (${status || 'Network'}). Retrying in ${delay}ms... (Attempt ${i + 1}/${maxRetries})`);
                await new Promise(resolve => setTimeout(resolve, delay));
                delay *= 2; // Exponential backoff
            } else {
                // Last attempt or not a retryable error, re-throw it
                throw error;
            }
        }
    }
    // This line should be unreachable due to the throw in the catch block on the final iteration
    throw new Error("An unexpected error occurred within the retry logic.");
};

/**
 * A utility to handle API errors in a standardized way.
 * It can process Response objects, ApiServiceError instances, or generic Errors.
 * @param error The error object to handle.
 * @returns A user-friendly error message string.
 */
export const handleApiError = (error: any): string => {
  if (error instanceof Response) {
    switch (error.status) {
      case 401:
        return 'Authentication failed. Please check your credentials.';
      case 429:
        return 'Too Many Requests. Please wait a moment and try again.';
      case 500:
        return 'Internal Server Error. The server encountered a problem.';
      case 503:
        return 'Service Unavailable. The AI provider is currently overloaded.';
      default:
        return `An unexpected network error occurred (Status: ${error.status}).`;
    }
  }

  if (error instanceof ApiServiceError) {
    return error.message;
  }

  if (error instanceof Error) {
    // Handle specific Gemini error messages
    if (error.message.includes('429')) return 'Rate limit exceeded. Please try again in a few seconds.';
    if (error.message.includes('500')) return 'Gemini internal error. Please try again.';
    if (error.message.includes('503')) return 'Gemini service overloaded. Please try again later.';
    return error.message;
  }

  // Fallback for non-Error objects or unknown types
  return 'An unexpected error occurred. Please try again.';
};

// services/localAiService.ts

export interface LocalAiResponse {
    resultText: string;
}

/**
 * Calls a local LLM endpoint (e.g., LM Studio, Ollama) compatible with the OpenAI Chat Completions API structure.
 * @param prompt The user input text.
 * @param endpoint The local API endpoint (e.g., http://localhost:1234/v1/chat/completions).
 * @param model The model identifier (optional, defaults to 'local-model').
 * @returns A promise resolving to the generated text.
 */
export const generateLocalContent = async (prompt: string, endpoint: string, model: string = 'local-model'): Promise<LocalAiResponse> => {
    if (!endpoint) {
        throw new Error('Local AI endpoint is not configured in settings.');
    }

    try {
        // Attempt to verify connectivity before full request (optional, but good for UX)
        // const check = await fetch(endpoint.replace('/chat/completions', '/models'), { method: 'GET' }).catch(() => null);

        const response = await fetch(endpoint, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                model: model,
                messages: [{ role: 'user', content: prompt }],
                temperature: 0.7,
                stream: false,
            }),
        });

        if (!response.ok) {
            throw new Error(`Local AI Server responded with status: ${response.status}`);
        }

        const data = await response.json();

        // Handle common OpenAI-compatible structures
        const resultText = data.choices?.[0]?.message?.content || data.choices?.[0]?.text || '';

        if (!resultText) {
            throw new Error("Received an empty response from Local AI.");
        }

        return { resultText };

    } catch (error: any) {
        console.error("Local AI Error:", error);

        let friendlyMessage = error.message;
        if (error.message.includes('Failed to fetch') || error.message.includes('NetworkError')) {
             friendlyMessage = `Could not connect to Local AI at ${endpoint}. Ensure your local server (LM Studio/Ollama) is running and CORS is enabled.`;
        }

        throw new Error(friendlyMessage);
    }
};

// hooks/useShuntProcessor.ts
import React, { useState, useCallback } from 'react';
import { ShuntAction, TokenUsage, PromptModuleKey, HistoryEntry } from '../types';
import { performShunt, executeModularPrompt, gradeOutput, synthesizeDocuments } from '../services/geminiService';
import { generateLocalContent } from '../services/localAiService';
import { parseSkillPackagePlan } from '../services/skillParser';
import { logFrontendError, ErrorSeverity, parseApiError } from '../utils/errorLogger';
import { useSubscription } from '../context/SubscriptionContext';
import { useSettings } from '../context/SettingsContext';
import { useMailbox } from '../context/MailboxContext';
import { sanitizeInput } from '../utils/security';
import { audioService } from '../services/audioService';
import { executeTool, ExecutionContext, ToolResult } from '../services/toolApi';
import { v4 as uuidv4 } from 'uuid';

interface UseShuntProcessorProps {
    inputText: string;
    setInputText: (text: string) => void;
    bulletinDocuments: { name: string; content: string }[];
    setBulletinDocuments: React.Dispatch<React.SetStateAction<{ name: string; content: string }[]>>;
    history: HistoryEntry[];
    setHistory: React.Dispatch<React.SetStateAction<HistoryEntry[]>>;
    initialPrompt: string;
    setInitialPrompt: (text: string) => void;
    priority: string;
    selectedModel: string;
    settings: any; // Using any to avoid circular dependency or complex type imports for now
    usage: any;
    tierDetails: any;
    incrementUsage: (metric: string) => void;
}

export const useShuntProcessor = ({
    inputText,
    setInputText,
    bulletinDocuments,
    setBulletinDocuments,
    history,
    setHistory,
    initialPrompt,
    setInitialPrompt,
    priority,
    selectedModel,
    settings,
    usage,
    tierDetails,
    incrementUsage
}: UseShuntProcessorProps) => {
    const [isLoading, setIsLoading] = useState(false);
    const [isEvolving, setIsEvolving] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [outputText, setOutputText] = useState('');
    const [activeShunt, setActiveShunt] = useState<string | null>(null);
    const [showAmplifyX2, setShowAmplifyX2] = useState(false);
    const [modulesForLastRun, setModulesForLastRun] = useState<string[] | null>(null);
    const [lastTokenUsage, setLastTokenUsage] = useState<TokenUsage | null>(null);
    const { deliverFiles } = useMailbox();

    // Helper to format bulletin context
    const getBulletinContext = useCallback(() => {
        if (bulletinDocuments.length === 0) return undefined;
        return bulletinDocuments
          .map(doc => `--- Reference Document: ${doc.name} ---\n\n${doc.content}`)
          .join('\n\n---\n\n');
    }, [bulletinDocuments]);

    const handleApiError = useCallback((e: any, telemetryContext: Record<string, any>) => {
        logFrontendError(e, ErrorSeverity.High, telemetryContext);
        const userFriendlyMessage = parseApiError(e);
        setError(userFriendlyMessage);
        setShowAmplifyX2(false);
        audioService.playSound('error');
    }, []);

    // --- Core Shunt Execution ---
    const handleShunt = useCallback(async (action: ShuntAction | string, textToProcess: string = inputText) => {
        if (tierDetails.shuntRuns !== 'unlimited' && usage.shuntRuns >= tierDetails.shuntRuns) {
            setError("You've reached your monthly limit for Shunt runs. Please upgrade your plan in the Subscription tab.");
            audioService.playSound('error');
            return;
        }

        setIsLoading(true);
        setError(null);
        setOutputText('');
        setModulesForLastRun(null);
        setShowAmplifyX2(false);
        setActiveShunt(action);
        audioService.playSound('send');

        if (history.length === 0) setInitialPrompt(textToProcess);

        if (action === ShuntAction.CALL_TOOL) {
             try {
                const { toolName, args } = JSON.parse(textToProcess);
                const executionContext: ExecutionContext = { agentId: 'shunt-direct-caller', permissions: ['system:admin', 'filesystem:read', 'filesystem:write', 'scratchpad:write', 'vcs:read', 'vcs:stage', 'vcs:branch', 'vcs:commit', 'execution:tests', 'execution:scripts'] };
                const result: ToolResult = await executeTool(toolName, args, executionContext);
                setOutputText(JSON.stringify(result, null, 2));
                audioService.playSound(result.success ? 'receive' : 'error');
            } catch (e: any) {
                handleApiError(e, { context: 'Shunt.handleShunt.tool_call', action });
            } finally {
                setIsLoading(false);
                setActiveShunt(null);
            }
            return;
        }

        const sanitizedText = settings.inputSanitizationEnabled ? sanitizeInput(textToProcess) : textToProcess;
        const bulletinContext = getBulletinContext();

        try {
            const { resultText, tokenUsage } = await performShunt(sanitizedText, action as ShuntAction, selectedModel, bulletinContext, priority, settings.promptInjectionGuardEnabled);

            if (action === ShuntAction.BUILD_A_SKILL) {
                const files = parseSkillPackagePlan(resultText);
                if (files.length > 0) {
                    await deliverFiles(files);
                    setOutputText(`✅ Skill package generated! ${files.length} files delivered to Mailbox.`);
                    audioService.playSound('success');
                } else {
                    setOutputText(`⚠️ Could not parse files. Raw output:\n${resultText}`);
                    audioService.playSound('error');
                }
            } else {
                setOutputText(resultText);
                if (action === ShuntAction.AMPLIFY && resultText) setShowAmplifyX2(true);
                audioService.playSound('receive');
            }

            incrementUsage('shuntRuns');
            setLastTokenUsage(tokenUsage);
        } catch (e: any) {
            // --- Fallback Mechanism ---
            if (settings.localModelFallbackEnabled) {
                console.warn("Primary API failed. Attempting Local Fallback...", e);
                try {
                    // Fallback logic doesn't support complex context/priority yet, just the raw prompt construction
                    const prompt = `${action}: ${sanitizedText}`; 
                    const { resultText } = await generateLocalContent(prompt, settings.lmStudioEndpoint);

                    setOutputText(resultText + "\n\n> ⚠️ **Generated via Local Model Fallback**");
                    audioService.playSound('success'); // Use success sound for fallback success
                    incrementUsage('shuntRuns');
                    return; // Exit successfully
                } catch (localError: any) {
                    console.error("Local fallback also failed:", localError);
                    // If local fails, we show the original error but maybe log the fallback failure
                    logFrontendError(localError, ErrorSeverity.Medium, { context: 'Shunt.localFallback', originalError: e.message });
                }
            }
            // If fallback disabled or failed, handle original error
            handleApiError(e, { context: 'Shunt.handleShunt', action, selectedModel, priority });
        } finally {
            setIsLoading(false);
            setActiveShunt(null);
        }
      }, [inputText, history.length, getBulletinContext, priority, selectedModel, settings, tierDetails, usage, incrementUsage, handleApiError, deliverFiles, setInitialPrompt]);

    // --- Modular Shunt Execution ---
    const handleModularShunt = useCallback(async (modules: Set<PromptModuleKey>) => {
        setIsLoading(true);
        setError(null);
        setOutputText('');
        setShowAmplifyX2(false);
        setActiveShunt('Modular Prompt');
        audioService.playSound('send');

        if (history.length === 0) setInitialPrompt(inputText);

        const sanitizedText = settings.inputSanitizationEnabled ? sanitizeInput(inputText) : inputText;
        const bulletinContext = getBulletinContext();

        try {
          setModulesForLastRun(Array.from(modules));
          const { resultText, tokenUsage } = await executeModularPrompt(sanitizedText, modules, bulletinContext, priority, settings.promptInjectionGuardEnabled);
          setOutputText(resultText);
          audioService.playSound('receive');
          incrementUsage('shuntRuns');
          setLastTokenUsage(tokenUsage);
        } catch (e: any) {
           handleApiError(e, { context: 'Shunt.handleModularShunt' });
        } finally {
          setIsLoading(false);
          setActiveShunt(null);
        }
    }, [inputText, history.length, getBulletinContext, priority, settings, incrementUsage, handleApiError, setInitialPrompt]);

    // --- Iterative Evolution ---
    const handleGradeAndIterate = useCallback(async () => {
        if (!outputText) return;
        setIsEvolving(true);
        try {
            const { score } = await gradeOutput(outputText, history.length > 0 ? history[history.length-1].prompt : initialPrompt);
            const newHistoryEntry: HistoryEntry = {
                id: uuidv4(),
                prompt: history.length > 0 ? history[history.length-1].output : initialPrompt,
                output: outputText,
                score: score,
            };
            setHistory(prev => [...prev, newHistoryEntry]);
            setInputText(outputText);
            setOutputText('');
            setError(null);
            setModulesForLastRun(null);
        } catch (e: any) {
            handleApiError(e, { context: 'Shunt.handleGradeAndIterate' });
        } finally {
            setIsEvolving(false);
        }
    }, [outputText, history, initialPrompt, setHistory, setInputText, handleApiError]);

    // --- Synthesis ---
    const handleSynthesize = useCallback(async () => {
        if (bulletinDocuments.length === 0) return;
        setIsLoading(true);
        setError(null);
        setOutputText('');
        setActiveShunt('Synthesize Notes');
        try {
            const combinedContent = bulletinDocuments.map(doc => `--- ${doc.name} ---\n${doc.content}`).join('\n\n');
            const { resultText } = await synthesizeDocuments(combinedContent, selectedModel);
            const newDoc = { name: `synthesis.md`, content: resultText };
            setBulletinDocuments(prev => [...prev, newDoc]);
            setInputText(resultText);
            setOutputText('Synthesis complete. Added to Bulletin Board.');
            audioService.playSound('success');
        } catch(e) { 
            handleApiError(e, {context: 'synthesize'}); 
        } finally { 
            setIsLoading(false); 
            setActiveShunt(null); 
        }
      }, [bulletinDocuments, selectedModel, handleApiError, setBulletinDocuments, setInputText]);

    return {
        isLoading,
        isEvolving,
        error,
        setError,
        outputText,
        setOutputText,
        activeShunt,
        setActiveShunt,
        showAmplifyX2,
        modulesForLastRun,
        lastTokenUsage,
        handleShunt,
        handleModularShunt,
        handleGradeAndIterate,
        handleSynthesize
    };
};

// hooks/useLmStudio.ts
import { useState, useCallback } from 'react';
import { generateLocalContent } from '../services/localAiService';

interface LmStudioResponse {
  resultText: string;
}

export const useLmStudio = () => {
    const [isLmStudioLoading, setIsLoading] = useState(false);
    const [lmStudioError, setLmStudioError] = useState<string | null>(null);

    const callLmStudio = useCallback(async (prompt: string, endpoint: string): Promise<LmStudioResponse> => {
        setIsLoading(true);
        setLmStudioError(null);

        try {
            const result = await generateLocalContent(prompt, endpoint);
            return result;
        } catch (error) {
            const errorMessage = error instanceof Error ? error.message : 'An unknown error occurred.';
            setLmStudioError(errorMessage);
            throw error;
        } finally {
            setIsLoading(false);
        }
    }, []);

    return { callLmStudio, isLmStudioLoading, lmStudioError };
};

// components/ErrorBoundary.tsx
import React, { ErrorInfo, ReactNode } from 'react';
import { logFrontendError, ErrorSeverity } from '../utils/errorLogger';
import { ArrowPathIcon, ErrorIcon } from './icons';
import { trackCustomEvent } from '../../styles/services/telemetry';

interface ErrorBoundaryProps {
  children: ReactNode;
  fallback?: ReactNode;
  componentName?: string; // To identify which part of the app crashed
}

interface ErrorBoundaryState {
  hasError: boolean;
  error?: Error;
}

class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  // Explicitly declare props to avoid TS errors in some environments
  declare props: Readonly<ErrorBoundaryProps>;

  state: ErrorBoundaryState = {
    hasError: false,
    error: undefined,
  };

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error(`Uncaught error in ${this.props.componentName || 'App'}:`, error, errorInfo);

    // Log to the centralized error logger (which handles Mia alerts)
    logFrontendError(error, ErrorSeverity.Critical, { 
        componentStack: errorInfo.componentStack,
        componentName: this.props.componentName || 'Unknown Component'
    });

    // Send direct telemetry event
    trackCustomEvent('ui_crash', {
        elementName: this.props.componentName || 'ErrorBoundary',
        elementType: 'react_component',
        context: {
            message: error.message,
            stack: error.stack,
            componentStack: errorInfo.componentStack
        }
    });
  }

  handleRetry = () => {
      this.setState({ hasError: false, error: undefined });
  };

  render(): React.ReactNode {
    if (this.state.hasError) {
      if (this.props.fallback) {
          return this.props.fallback;
      }

      return (
        <div className="flex flex-col items-center justify-center h-full p-6 bg-gray-900/80 border border-red-900/50 rounded-lg text-center animate-fade-in">
          <div className="p-3 bg-red-900/20 rounded-full mb-4">
            <ErrorIcon className="w-8 h-8 text-red-500" />
          </div>
          <h2 className="text-lg font-bold text-red-400 mb-2">Render Error in {this.props.componentName || 'View'}</h2>
          <p className="text-sm text-gray-400 mb-6 max-w-md">
            The application encountered a critical error while rendering this component. 
            Telemetry has been dispatched to the governance engine.
          </p>

          {this.state.error && (
            <details className="w-full max-w-lg mb-6 text-left bg-black/50 p-3 rounded border border-red-900/30">
                <summary className="text-xs text-red-300 cursor-pointer hover:text-red-200">View Error Details</summary>
                <pre className="mt-2 text-[10px] font-mono text-red-300/70 whitespace-pre-wrap overflow-auto max-h-32">
                    {this.state.error.toString()}
                    {this.state.error.stack}
                </pre>
            </details>
          )}

          <button 
            onClick={this.handleRetry}
            className="flex items-center gap-2 px-4 py-2 bg-red-600 hover:bg-red-500 text-white rounded-md transition-colors font-medium text-sm shadow-lg shadow-red-900/20"
          >
            <ArrowPathIcon className="w-4 h-4" />
            Attempt Recovery
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

// components/mission_control/SystemDiagnostics.tsx
import React, { useEffect, useState } from 'react';
import { runDiagnostics } from '../../services/testRunner';
import { ShieldCheckIcon, BoltIcon, CheckCircleIcon, ErrorIcon } from '../icons';
import Loader from '../Loader';
import TabFooter from '../common/TabFooter';

const SystemDiagnostics: React.FC = () => {
    const [logs, setLogs] = useState<string[]>([]);
    const [isRunning, setIsRunning] = useState(false);
    const [status, setStatus] = useState<'idle' | 'success' | 'failure'>('idle');

    const handleRunDiagnostics = async () => {
        setIsRunning(true);
        setStatus('idle');
        setLogs(['Initializing diagnostic sequence...', 'Loading schema definitions...']);

        try {
            const report = await runDiagnostics();
            setLogs(report.split('\n'));
            setStatus(report.includes('FAILED') ? 'failure' : 'success');
        } catch (e) {
            setLogs(prev => [...prev, `CRITICAL SYSTEM FAILURE: ${e}`]);
            setStatus('failure');
        } finally {
            setIsRunning(false);
        }
    };

    // Auto-run on mount
    useEffect(() => {
        handleRunDiagnostics();
    }, []);

    return (
        <div className="flex flex-col h-full bg-gray-900/30">
            <div className="p-4 md:p-6 border-b border-gray-700/50 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h2 className="text-2xl font-semibold text-white flex items-center gap-3">
                        <ShieldCheckIcon className={`w-7 h-7 ${status === 'success' ? 'text-green-400' : status === 'failure' ? 'text-red-400' : 'text-gray-400'}`} />
                        System Resilience & Type Monitor
                    </h2>
                    <p className="text-gray-400 mt-1 text-sm">
                        Runtime verification of Zod schemas, API contracts, and internal type consistency.
                    </p>
                </div>
                <button
                    onClick={handleRunDiagnostics}
                    disabled={isRunning}
                    className="px-4 py-2 bg-gray-700 hover:bg-gray-600 text-white rounded-md flex items-center gap-2 transition-colors disabled:opacity-50"
                >
                    {isRunning ? <Loader className="w-4 h-4" /> : <BoltIcon className="w-4 h-4 text-cyan-400" />}
                    {isRunning ? 'Running Tests...' : 'Re-Run Diagnostics'}
                </button>
            </div>

            <div className="flex-grow p-4 md:p-6 overflow-hidden">
                <div className="h-full bg-black/50 border border-gray-700/50 rounded-lg p-4 font-mono text-sm overflow-y-auto custom-scrollbar shadow-inner">
                    {logs.map((log, index) => {
                        const isPass = log.includes('PASSED');
                        const isFail = log.includes('FAILED');
                        const isHeader = log.startsWith('---');

                        return (
                            <div key={index} className={`mb-1 flex items-start gap-2 ${isHeader ? 'text-gray-500 mt-4 mb-2' : ''}`}>
                                {!isHeader && (
                                    <span className="mt-1 flex-shrink-0">
                                        {isPass ? <CheckCircleIcon className="w-3 h-3 text-green-500" /> : 
                                         isFail ? <ErrorIcon className="w-3 h-3 text-red-500" /> : 
                                         <span className="w-3 h-3 block" />}
                                    </span>
                                )}
                                <span className={`break-all ${isPass ? 'text-green-300' : isFail ? 'text-red-300 font-bold' : 'text-gray-300'}`}>
                                    {log}
                                </span>
                            </div>
                        );
                    })}
                    {isRunning && (
                        <div className="flex items-center gap-2 mt-2 text-cyan-400 animate-pulse">
                            <span className="w-1.5 h-1.5 bg-cyan-400 rounded-full" />
                            Executing next test suite...
                        </div>
                    )}
                </div>
            </div>
            <TabFooter />
        </div>
    );
};

export default SystemDiagnostics;

