import React from 'react';
import Mermaid from './Mermaid';
import DOMPurify from 'dompurify';

interface MarkdownRendererProps {
  content: string | undefined | null;
}

// Strict Allow-list for DOMPurify to prevent XSS (P0 Priority)
const PURIFY_CONFIG = {
    ALLOWED_TAGS: ['h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'p', 'span', 'div', 'ul', 'ol', 'li', 'b', 'i', 'strong', 'em', 'code', 'pre', 'br', 'hr', 'blockquote', 'a', 'img', 'table', 'thead', 'tbody', 'tr', 'th', 'td'],
    ALLOWED_ATTR: ['href', 'src', 'alt', 'title', 'class', 'target'],
    FORBID_TAGS: ['script', 'iframe', 'object', 'embed', 'form', 'input', 'button', 'style'], // Explicitly forbid dangerous tags
};

// Hook to ensure links open in new tabs securely (prevent tabnabbing)
DOMPurify.addHook('afterSanitizeAttributes', (node) => {
    if ('target' in node && node.getAttribute('target') === '_blank') {
        node.setAttribute('rel', 'noopener noreferrer');
    }
});

const MarkdownRenderer: React.FC<MarkdownRendererProps> = ({ content }) => {
    // Edge Case: Handle non-string or null/undefined content gracefully
    if (typeof content !== 'string') {
        if (content === null || content === undefined) return null;
        return <div className="text-gray-500 italic">Invalid content type: {typeof content}</div>;
    }

    if (!content.trim()) return null;

    try {
        // 1. Split by code blocks first to preserve their content without processing
        const parts = content.split(/(```[\s\S]*?```)/g);

        const renderText = (text: string) => {
            try {
                // We rely on DOMPurify for the heavy lifting of XSS prevention.
                // However, we still want to convert Markdown syntax to HTML.

                // Simple Markdown Conversion (Regex-based for basic formatting)

                let html = text
                     // Escape HTML entities first to prevent injection via the parser
                    .replace(/&/g, "&amp;")
                    .replace(/</g, "&lt;")
                    .replace(/>/g, "&gt;")

                    // Headings
                    .replace(/^### (.*$)/gim, '<h3>$1</h3>')
                    .replace(/^## (.*$)/gim, '<h2>$1</h2>')
                    .replace(/^# (.*$)/gim, '<h1>$1</h1>')

                    // Bold
                    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')

                    // Italic
                    .replace(/\*(.*?)\*/g, '<em>$1</em>')

                    // Unordered lists
                    .replace(/^\* (.*$)/gim, '<li>$1</li>')
                    .replace(/((?:<li>.*<\/li>\s*(?:\n|$))+)/g, '<ul>$1</ul>')

                    // Restore specifically whitelisted HTML tags if they were escaped above
                    // This acts as a controlled un-escape for our generated tags
                    .replace(/&lt;(\/?)(h[1-6]|strong|em|ul|li)&gt;/g, '<$1$2>');

                // Paragraphs: Wrap lines that aren't part of other blocks
                html = html.split('\n').map(line => {
                    if (line.trim() === '') return '<br />';
                    if (line.match(/^\s*<(\/)?(h[1-6]|ul|li)/)) { 
                        return line;
                    }
                    return `<p>${line}</p>`;
                }).join('');

                // FINAL SECURITY PASS: Sanitize the generated HTML
                const sanitizedHtml = DOMPurify.sanitize(html, PURIFY_CONFIG);

                return <div dangerouslySetInnerHTML={{ __html: sanitizedHtml as string }} />;
            } catch (err) {
                console.error("Markdown parsing error:", err);
                return <div className="text-red-400 text-xs whitespace-pre-wrap">{text}</div>;
            }
        };

        return (
            <div className="prose prose-invert prose-sm max-w-none">
                {parts.map((part, index) => {
                    if (!part) return null;
                    if (part.startsWith('```') && part.endsWith('```')) {
                        const code = part.slice(3, -3).trim();
                        const languageMatch = code.match(/^[a-z]+\n/);
                        const language = languageMatch ? languageMatch[0].trim() : '';
                        const actualCode = language ? code.substring(code.indexOf('\n') + 1) : code;

                        if (language === 'mermaid') {
                            return (
                                <div key={index} className="my-4 not-prose bg-gray-900/50 p-4 rounded-lg flex justify-center">
                                    <Mermaid chart={actualCode} />
                                </div>
                            );
                        }

                        // Code blocks are safe to render as text in a pre tag
                        return (
                            <div key={index} className="bg-black/50 rounded-lg my-4 not-prose">
                                {language && <div className="text-xs text-gray-400 px-4 py-2 border-b border-gray-600/50">{language}</div>}
                                <pre className="p-4 text-sm text-gray-200 overflow-x-auto whitespace-pre-wrap font-mono">
                                    <code>{actualCode}</code>
                                </pre>
                            </div>
                        );
                    }
                    return <div key={index}>{renderText(part)}</div>;
                })}
            </div>
        );
    } catch (e) {
        // Fallback for catastrophic failure in split or map
        console.error("Critical Markdown Renderer Failure:", e);
        return (
            <div className="p-4 bg-red-900/20 border border-red-500/50 rounded text-gray-300">
                <p className="font-bold text-red-400 mb-2">Renderer Crashed</p>
                <pre className="whitespace-pre-wrap font-mono text-xs">{content}</pre>
            </div>
        );
    }
};

export default React.memo(MarkdownRenderer);

