export const runDiagnostics = async (): Promise<string> => {
    const logs: string[] = [];

    const log = (msg: string) => logs.push(msg);
    const pass = (msg: string) => log(`✅ PASSED: ${msg}`);
    const fail = (msg: string, error?: any) => log(`❌ FAILED: ${msg} ${error ? `(${error})` : ''}`);

    log("Running Type Error Tests (Schema Validation)...");
    log("------------------------------------------------");

    // 1. Token Usage Schema Test
    try {
        tokenUsageSchema.parse({
            prompt_tokens: 10,
            completion_tokens: 20,
            total_tokens: 30,
            model: 'gemini-pro'
        });
        pass("TokenUsage Schema (Valid Data)");
    } catch (e) {
        fail("TokenUsage Schema (Valid Data)", e);
    }

    // 1b. Token Usage Edge Case (Strings/Missing)
    try {
        const result = tokenUsageSchema.parse({
            prompt_tokens: "100", // String should be coerced
            // completion_tokens missing, should default
            total_tokens: 100,
            model: 'gemini-flash'
        });
        if (result.prompt_tokens === 100 && result.completion_tokens === 0) {
            pass("TokenUsage Resilience (Coercion & Defaults)");
        } else {
            fail("TokenUsage Resilience (Values incorrect)", result);
        }
    } catch (e) {
        fail("TokenUsage Resilience (Threw Error)", e);
    }

    // 2. Implementation Task Schema Test
    try {
        implementationTaskSchema.parse({
            filePath: "src/test.ts",
            description: "A test file",
            newContent: "console.log('test')"
        });
        pass("ImplementationTask Schema (Valid Data)");
    } catch (e) {
        fail("ImplementationTask Schema (Valid Data)", e);
    }

    // 3. Implementation Task Schema Test (Invalid)
    try {
        implementationTaskSchema.parse({
            description: "Missing file path"
        });
        fail("ImplementationTask Schema (Invalid Data - Should catch missing filePath)");
    } catch (e) {
        pass("ImplementationTask Schema (Invalid Data - Caught expected error)");
    }

    // 4. Gemini Development Plan Schema Test
    try {
        geminiDevelopmentPlanResponseSchema.parse({
            clarifyingQuestions: ["Why?"],
            architecturalProposal: "Build the thing.",
            implementationTasks: [{
                filePath: "src/main.ts",
                description: "Main entry",
                newContent: "import App from './App';"
            }],
            testCases: ["Run npm test"],
            dataSchema: "interface User { id: string; }"
        });
        pass("GeminiDevelopmentPlan Schema (Valid Data)");
    } catch (e) {
        fail("GeminiDevelopmentPlan Schema (Valid Data)", e);
    }

    // 5. Edge Case: Empty Plan Object
    try {
        // Should use defaults for everything
        const result = geminiDevelopmentPlanResponseSchema.parse({}); 
        if (result.clarifyingQuestions.length === 0 && result.implementationTasks.length === 0) {
            pass("GeminiDevelopmentPlan Resilience (Empty Input)");
        } else {
            fail("GeminiDevelopmentPlan Resilience (Defaults check failed)", result);
        }
    } catch (e) {
        fail("GeminiDevelopmentPlan Resilience (Empty Input Threw Error)", e);
    }

    log("------------------------------------------------");
    log("Diagnostics Complete.");

    return logs.join('\n');
};

// utils/errorLogger.ts
import { v4 as uuidv4 } from 'uuid';
import { MiaAlert } from '../types';
import { appEventBus } from '../lib/eventBus';

export enum ErrorSeverity {
  Low = 'low',
  Medium = 'medium',
  High = 'high',
  Critical = 'critical',
}

/**
 * Creates a user-friendly, actionable error message from a raw API error object.
 * @param error The error object caught from an API call.
 * @returns A string containing a user-friendly message.
 */
export const parseApiError = (error: any): string => {
    let userFriendlyMessage = 'An unexpected error occurred. Please try again or check the developer console for details.';

    if (error && typeof error.toString === 'function') {
        const errorMessage = error.toString().toLowerCase();

        // Specific tensor mismatch error handling
        if (errorMessage.includes('size of tensor a') && errorMessage.includes('match the size of tensor b')) {
            return "Model Tensor Mismatch: The local AI model encountered a shape mismatch (e.g., 1024 vs 1280). This usually indicates incompatible model weights or an issue with the local inference engine configuration.";
        }

        if (errorMessage.includes('quota')) {
            return "You've exceeded your API usage quota for the current period. Please check your usage or upgrade your plan in the 'Subscription' tab.";
        }
        if (errorMessage.includes('429') || errorMessage.includes('resource_exhausted')) {
            return 'API rate limit exceeded. The service is temporarily busy. Please wait a moment before trying again.';
        }
        if (errorMessage.includes('api key')) {
            return 'There appears to be an issue with the API key configuration. Please ensure it is set up correctly.';
        }
        if (errorMessage.includes('400') || errorMessage.includes('invalid')) {
            return 'Invalid request sent to the API. This may be due to malformed input.';
        }
        if (error.message) {
            // Extract the core message from Gemini's formatted error string like "[400 Bad Request] The model ... does not exist."
            const match = error.message.match(/\[\d{3}.*?\]\s*(.*)/);
            if (match) {
                return match[1];
            }
            return error.message;
        }
    }
    return userFriendlyMessage;
}

export const logFrontendError = (
  error: any,
  severity: ErrorSeverity = ErrorSeverity.Medium,
  context?: Record<string, any>
) => {
  let message: string;
  let stack: string | undefined;
  let title: string = "An error occurred";

  if (error instanceof Error) {
    message = error.message;
    stack = error.stack;
    title = error.name;
  } else if (typeof error === 'string') {
    message = error;
  } else if (error instanceof Event && error.type === 'error') {
    message = (error as ErrorEvent).message || 'An unknown error occurred from an Event.';
    title = 'Unhandled Error Event';
  } else {
    title = 'Unknown Error';
    if (typeof error === 'object' && error !== null) {
        if (error.message) {
            message = String(error.message);
        } else {
            try {
                message = JSON.stringify(error);
            } catch {
                message = 'An un-serializable object was thrown.';
            }
        }
        if (error.stack) {
            stack = String(error.stack);
        }
    } else {
        message = 'An unknown value was thrown.';
    }
  }

  const errorContext = {
    ...context,
    stack: stack,
    timestamp: new Date().toISOString(),
  };

  // Log to console for immediate developer feedback.
  // Using multiple arguments is more robust against loggers that stringify objects.
  console.error('[AetherShunt ErrorLogger] - An error was caught:');
  console.error('  Severity:', severity);
  console.error('  Title:', title);
  console.error('  Message:', message);
  console.error('  Context:', errorContext);

  // Map severity to Mia's alert levels
  let miaSeverity: 'info' | 'warning' | 'critical';
  switch (severity) {
    case ErrorSeverity.Critical:
    case ErrorSeverity.High:
      miaSeverity = 'critical';
      break;
    case ErrorSeverity.Medium:
      miaSeverity = 'warning';
      break;
    case ErrorSeverity.Low:
    default:
      miaSeverity = 'info';
      break;
  }

  // Create an alert for Mia to handle, but only for medium severity and above
  if (severity === ErrorSeverity.Medium || severity === ErrorSeverity.High || severity === ErrorSeverity.Critical) {
    const alert: MiaAlert = {
      id: uuidv4(),
      type: 'error_diagnosis',
      severity: miaSeverity,
      title: title,
      message: message,
      timestamp: new Date().toISOString(),
      context: errorContext,
      actions: [{ label: 'Diagnose Error', actionType: 'diagnose' }]
    };
    appEventBus.emit('mia-alert', alert);
  }
};

export const setupGlobalErrorHandlers = () => {
  window.onerror = (message, source, lineno, colno, error) => {
    // Some browsers pass an Error object, others just the message. logFrontendError handles both.
    logFrontendError(error || message, ErrorSeverity.Critical, {
      source,
      lineno,
      colno,
      context: 'window.onerror',
    });
    // Prevent the default browser console error log
    return true;
  };

  window.onunhandledrejection = (event) => {
    logFrontendError(event.reason, ErrorSeverity.High, {
      context: 'window.onunhandledrejection',
    });
  };
};

import { z } from 'zod';
import { geminiDevelopmentPlanResponseSchema, implementationTaskSchema, tokenUsageSchema } from '../types/schemas';
import { generateLocalContent } from './localAiService';

export const runDiagnostics = async (localEndpoint?: string): Promise<string> => {
    const logs: string[] = [];

    const log = (msg: string) => logs.push(msg);
    const pass = (msg: string) => log(`✅ PASSED: ${msg}`);
    const fail = (msg: string, error?: any) => log(`❌ FAILED: ${msg} ${error ? `(${error})` : ''}`);
    const warn = (msg: string) => log(`⚠️ WARNING: ${msg}`);

    log("Running System Diagnostics & Type Integrity Check");
    log("------------------------------------------------");

    // --- 1. Schema Validation Tests ---
    log("[1/3] Verifying Zod Schemas...");

    // Token Usage
    try {
        tokenUsageSchema.parse({
            prompt_tokens: "100", // Test coercion
            total_tokens: 100,
            model: 'gemini-flash'
        });
        pass("TokenUsage Schema (Coercion)");
    } catch (e) {
        fail("TokenUsage Schema", e);
    }

    // Gemini Plan
    try {
        const result = geminiDevelopmentPlanResponseSchema.parse({}); 
        if (result.clarifyingQuestions.length === 0) {
            pass("GeminiResponse Schema (Defaults)");
        } else {
            fail("GeminiResponse Schema (Defaults failed)");
        }
    } catch (e) {
        fail("GeminiResponse Schema", e);
    }

    // --- 2. Local AI Health Check ---
    log("\n[2/3] Checking Local AI Connectivity...");
    if (localEndpoint) {
        try {
            log(`Pinging Local AI at: ${localEndpoint}`);
            const startTime = Date.now();
            // Simple probe to check if model is loaded and tensors align
            await generateLocalContent("ping", localEndpoint); 
            const latency = Date.now() - startTime;
            pass(`Local AI is online and responding (${latency}ms)`);
        } catch (e: any) {
            const errStr = e.toString().toLowerCase();
            if (errStr.includes('tensor') && errStr.includes('match')) {
                fail("Tensor Dimension Mismatch detected!", "Your local model's embedding dimensions (e.g., 1024 vs 1280) do not match the expected configuration. Please check your model loading parameters in LM Studio/Ollama.");
            } else if (errStr.includes('fetch') || errStr.includes('connect')) {
                fail("Local AI unreachable.", "Is LM Studio/Ollama running? Check CORS settings.");
            } else {
                fail("Local AI Error", e.message);
            }
        }
    } else {
        warn("Local AI Endpoint not configured. Skipping health check.");
    }

    // --- 3. Environment & Config ---
    log("\n[3/3] Checking Environment Config...");
    if (process.env.API_KEY) {
        pass("Google API Key is present.");
    } else {
        fail("Google API Key is MISSING from process.env");
    }

    log("------------------------------------------------");
    log("Diagnostics Complete.");

    return logs.join('\n');
};

