import React, { useState, useMemo } from 'react';
import { HallmarkFix } from '../../../types';
import { v4 as uuidv4 } from 'uuid';
import { BoltIcon, CodeIcon, XMarkIcon, CheckIcon, CopyIcon, DocumentDuplicateIcon, FolderIcon, DeviceFloppyIcon } from '../icons';
import { useTelemetry } from '../../../styles/services/context/TelemetryContext';

interface FixEngineProps {
    fixes: HallmarkFix[];
    onUpdateFixes: (fixes: HallmarkFix[]) => void;
}

const FixEngine: React.FC<FixEngineProps> = ({ fixes, onUpdateFixes }) => {
    const [selectedId, setSelectedId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [editMode, setEditMode] = useState(false);
    const [draftFix, setDraftFix] = useState<HallmarkFix | null>(null);
    const [copied, setCopied] = useState(false);
    const { updateTelemetryContext } = useTelemetry();

    const filteredFixes = useMemo(() => {
        if (!searchTerm) return fixes;
        const term = searchTerm.toLowerCase();
        return fixes.filter(f => 
            f.title.toLowerCase().includes(term) || 
            f.description.toLowerCase().includes(term) ||
            f.tags.some(t => t.toLowerCase().includes(term))
        );
    }, [fixes, searchTerm]);

    const handleSelect = (fix: HallmarkFix) => {
        setSelectedId(fix.id);
        setEditMode(false);
        setDraftFix(null);
    };

    const handleCreate = () => {
        const newFix: HallmarkFix = {
            id: uuidv4(),
            title: 'New Capability',
            description: '',
            codeSnippet: '',
            tags: [],
            timestamp: new Date().toISOString(),
        };
        setDraftFix(newFix);
        setSelectedId(newFix.id);
        setEditMode(true);
    };

    const handleEdit = () => {
        const current = fixes.find(f => f.id === selectedId);
        if (current) {
            setDraftFix({ ...current });
            setEditMode(true);
        }
    };

    const handleSave = () => {
        if (!draftFix) return;

        if (fixes.some(f => f.id === draftFix.id)) {
            // Update existing
            onUpdateFixes(fixes.map(f => f.id === draftFix.id ? draftFix : f));
        } else {
            // Create new
            onUpdateFixes([...fixes, draftFix]);
        }
        setEditMode(false);
        setDraftFix(null);
    };

    const handleDelete = (id: string) => {
        if (window.confirm("Are you sure you want to delete this capability?")) {
            onUpdateFixes(fixes.filter(f => f.id !== id));
            if (selectedId === id) setSelectedId(null);
        }
    };

    const handleCopy = (content: string) => {
        navigator.clipboard.writeText(content);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    const handleBoostContext = (fix: HallmarkFix) => {
        updateTelemetryContext({ 
            contextDetails: { 
                activeCapability: fix.title,
                capabilityContent: fix.codeSnippet 
            } 
        });
        alert(`System Accelerated: "${fix.title}" injected into global context.`);
    };

    const selectedFix = editMode ? draftFix : fixes.find(f => f.id === selectedId);

    return (
        <div className="bg-gray-800/50 rounded-lg border border-gray-700/50 flex h-full shadow-lg overflow-hidden">
            {/* Left Sidebar: List */}
            <div className="w-1/3 border-r border-gray-700/50 flex flex-col bg-gray-900/30">
                <div className="p-3 border-b border-gray-700/50 flex items-center justify-between">
                    <h3 className="font-semibold text-gray-200 flex items-center gap-2">
                        <FolderIcon className="w-5 h-5 text-cyan-400" />
                        Library
                    </h3>
                    <button onClick={handleCreate} className="p-1.5 bg-fuchsia-600 text-white rounded hover:bg-fuchsia-500 transition-colors" title="Create New Capability">
                        <BoltIcon className="w-4 h-4" />
                    </button>
                </div>
                <div className="p-3 border-b border-gray-700/50">
                    <input 
                        type="text" 
                        value={searchTerm} 
                        onChange={(e) => setSearchTerm(e.target.value)}
                        placeholder="Search capabilities..."
                        className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-xs text-gray-300 focus:outline-none focus:border-cyan-500"
                    />
                </div>
                <div className="flex-grow overflow-y-auto p-2 space-y-1">
                    {filteredFixes.map(fix => (
                        <button 
                            key={fix.id} 
                            onClick={() => handleSelect(fix)}
                            className={`w-full text-left p-3 rounded-md transition-all border ${selectedId === fix.id ? 'bg-cyan-900/20 border-cyan-500/50' : 'bg-transparent border-transparent hover:bg-gray-800/50'}`}
                        >
                            <div className="flex justify-between items-start">
                                <span className={`font-medium text-sm ${selectedId === fix.id ? 'text-cyan-300' : 'text-gray-300'}`}>{fix.title}</span>
                                <span className="text-[10px] text-gray-500">{new Date(fix.timestamp).toLocaleDateString()}</span>
                            </div>
                            <div className="mt-1 flex flex-wrap gap-1">
                                {fix.tags.map(tag => <span key={tag} className="text-[10px] bg-gray-800 text-gray-400 px-1.5 rounded">{tag}</span>)}
                            </div>
                        </button>
                    ))}
                    {filteredFixes.length === 0 && (
                        <div className="text-center text-gray-500 py-8 text-xs italic">
                            No capabilities found.
                        </div>
                    )}
                </div>
            </div>

            {/* Right Panel: Detail/Edit */}
            <div className="w-2/3 flex flex-col bg-gray-800/20">
                {selectedFix ? (
                    <>
                        <header className="p-4 border-b border-gray-700/50 flex justify-between items-center bg-gray-900/20">
                            {editMode ? (
                                <input 
                                    value={selectedFix.title} 
                                    onChange={(e) => setDraftFix({...selectedFix, title: e.target.value})}
                                    className="bg-gray-900 border border-gray-700 text-lg font-bold text-white px-2 py-1 rounded w-full mr-4"
                                    placeholder="Capability Title"
                                />
                            ) : (
                                <h2 className="text-lg font-bold text-white">{selectedFix.title}</h2>
                            )}

                            <div className="flex gap-2">
                                {editMode ? (
                                    <>
                                        <button onClick={() => setEditMode(false)} className="p-2 text-gray-400 hover:text-white" title="Cancel">
                                            <XMarkIcon className="w-5 h-5" />
                                        </button>
                                        <button onClick={handleSave} className="p-2 bg-green-600 text-white rounded hover:bg-green-500" title="Save">
                                            <DeviceFloppyIcon className="w-5 h-5" />
                                        </button>
                                    </>
                                ) : (
                                    <>
                                        <button onClick={() => handleBoostContext(selectedFix)} className="p-2 bg-purple-600/50 text-purple-200 border border-purple-500/50 rounded hover:bg-purple-600 hover:text-white transition-colors" title="Accelerate State: Inject this capability into active context">
                                            <BoltIcon className="w-5 h-5" />
                                        </button>
                                        <button onClick={handleEdit} className="p-2 text-gray-400 hover:text-cyan-400" title="Edit">
                                            <DocumentDuplicateIcon className="w-5 h-5" />
                                        </button>
                                        <button onClick={() => handleDelete(selectedFix.id)} className="p-2 text-gray-400 hover:text-red-400" title="Delete">
                                            <XMarkIcon className="w-5 h-5" />
                                        </button>
                                    </>
                                )}
                            </div>
                        </header>

                        <div className="flex-grow p-4 overflow-y-auto space-y-4">
                            {/* Tags Input */}
                            <div>
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1 block">Tags (comma separated)</label>
                                {editMode ? (
                                    <input 
                                        value={selectedFix.tags.join(', ')} 
                                        onChange={(e) => setDraftFix({...selectedFix, tags: e.target.value.split(',').map(t => t.trim()).filter(Boolean)})}
                                        className="w-full bg-gray-900/50 border border-gray-700 rounded p-2 text-sm text-gray-300"
                                        placeholder="e.g., react, fix, performance"
                                    />
                                ) : (
                                    <div className="flex gap-2">
                                        {selectedFix.tags.map(tag => (
                                            <span key={tag} className="bg-fuchsia-900/30 text-fuchsia-300 px-2 py-1 rounded text-xs border border-fuchsia-500/20">{tag}</span>
                                        ))}
                                    </div>
                                )}
                            </div>

                            {/* Description */}
                            <div>
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1 block">Description / Context</label>
                                {editMode ? (
                                    <textarea 
                                        value={selectedFix.description} 
                                        onChange={(e) => setDraftFix({...selectedFix, description: e.target.value})}
                                        className="w-full h-24 bg-gray-900/50 border border-gray-700 rounded p-3 text-sm text-gray-300 resize-none font-sans"
                                        placeholder="Explain the problem and the solution..."
                                    />
                                ) : (
                                    <p className="text-gray-300 text-sm whitespace-pre-wrap leading-relaxed">{selectedFix.description || 'No description provided.'}</p>
                                )}
                            </div>

                            {/* Code Snippet */}
                            <div className="flex-grow flex flex-col min-h-[200px]">
                                <div className="flex justify-between items-center mb-1">
                                    <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block">Solution / Pattern</label>
                                    {!editMode && (
                                        <button onClick={() => handleCopy(selectedFix.codeSnippet)} className="text-xs flex items-center gap-1 text-gray-400 hover:text-white">
                                            {copied ? <CheckIcon className="w-3 h-3 text-green-400" /> : <CopyIcon className="w-3 h-3" />}
                                            {copied ? 'Copied' : 'Copy Code'}
                                        </button>
                                    )}
                                </div>
                                {editMode ? (
                                    <textarea 
                                        value={selectedFix.codeSnippet} 
                                        onChange={(e) => setDraftFix({...selectedFix, codeSnippet: e.target.value})}
                                        className="flex-grow w-full bg-black/50 border border-gray-700 rounded p-3 text-xs font-mono text-green-300 resize-none focus:outline-none focus:border-cyan-500"
                                        placeholder="// Enter code fix or pattern here..."
                                    />
                                ) : (
                                    <pre className="flex-grow w-full bg-black/50 border border-gray-700 rounded p-3 text-xs font-mono text-gray-300 overflow-auto whitespace-pre-wrap">
                                        {selectedFix.codeSnippet}
                                    </pre>
                                )}
                            </div>
                        </div>
                    </>
                ) : (
                    <div className="flex flex-col items-center justify-center h-full text-gray-500">
                        <div className="w-16 h-16 bg-gray-800 rounded-full flex items-center justify-center mb-4">
                            <BoltIcon className="w-8 h-8 text-gray-600" />
                        </div>
                        <h3 className="text-lg font-semibold text-gray-400">Capability Engine</h3>
                        <p className="text-sm mt-2 max-w-xs text-center">Select a capability from the library or create a new one to accelerate your workflow.</p>
                        <button onClick={handleCreate} className="mt-6 px-4 py-2 bg-gray-700 hover:bg-gray-600 text-white rounded transition-colors text-sm font-medium">
                            Create New Capability
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
};

export default FixEngine;

// components/weaver/Weaver.tsx
import React, { useState, useCallback, useEffect } from 'react';
import MemoryPanel from './MemoryPanel';
import PlanDisplay from './PlanDisplay';
import FixEngine from './FixEngine';
import { generateDevelopmentPlan } from '../../services/geminiService';
import { GeminiResponse, Documentation, HallmarkFix } from '../../types';
import { useTelemetry } from '../../context/TelemetryContext';
import { INITIAL_DOCUMENTATION } from '../../context/constants';
import { SparklesIcon, XMarkIcon, BoltIcon, BookIcon } from '../icons';
import Loader from '../Loader';
import { audioService } from '../../services/audioService';
import { useSubscription } from '../../context/SubscriptionContext';
import { parseApiError } from '../../utils/errorLogger';
import { useRealTimePrompt } from '../../hooks/useRealTimePrompt';
import { RealTimeFeedback } from '../common/RealTimeFeedback';

const WEAVER_MEMORY_STORAGE_KEY = 'weaver-project-memory';
const WEAVER_FIXES_STORAGE_KEY = 'weaver_hallmark_fixes';

const loadDocumentation = (): Documentation => {
    try {
        const stored = localStorage.getItem(WEAVER_MEMORY_STORAGE_KEY);
        if (stored) {
            return { ...INITIAL_DOCUMENTATION, ...JSON.parse(stored) };
        }
    } catch (e) {
        console.error("Failed to load Weaver memory:", e);
    }
    return INITIAL_DOCUMENTATION;
};

const Weaver: React.FC = () => {
  const [goal, setGoal] = useState(() => localStorage.getItem('weaver_goal') || '');
  const [plan, setPlan] = useState<GeminiResponse | null>(() => {
    try {
        const saved = localStorage.getItem('weaver_plan');
        return saved ? JSON.parse(saved) : null;
    } catch { return null; }
  });
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [documentation, setDocumentation] = useState<Documentation>(loadDocumentation);
  const [newlyGenerated, setNewlyGenerated] = useState(false);

  // State for Capability Engine
  const [fixes, setFixes] = useState<HallmarkFix[]>(() => {
      try {
          const saved = localStorage.getItem(WEAVER_FIXES_STORAGE_KEY);
          return saved ? JSON.parse(saved) : [];
      } catch { return []; }
  });
  const [leftPanelMode, setLeftPanelMode] = useState<'memory' | 'engine'>('memory');

  const { telemetryService, versionControlService, updateTelemetryContext } = useTelemetry();
  const { usage, tierDetails, incrementUsage } = useSubscription();

  // RT Prompt Hook
  const { feedback, isLoading: isRTLoading, applyFeedback, discardFeedback } = useRealTimePrompt(goal, setGoal);

  useEffect(() => {
    updateTelemetryContext({ tab: 'Weaver' });
  }, [updateTelemetryContext]);

  useEffect(() => {
      try {
          localStorage.setItem(WEAVER_MEMORY_STORAGE_KEY, JSON.stringify(documentation));
      } catch (e) {
          console.error("Failed to save Weaver memory:", e);
      }
  }, [documentation]);

  useEffect(() => {
      try {
          localStorage.setItem(WEAVER_FIXES_STORAGE_KEY, JSON.stringify(fixes));
      } catch (e) { console.error("Failed to save fixes:", e); }
  }, [fixes]);

  useEffect(() => { localStorage.setItem('weaver_goal', goal); }, [goal]);
  useEffect(() => {
      if (plan) {
          localStorage.setItem('weaver_plan', JSON.stringify(plan));
      } else {
          localStorage.removeItem('weaver_plan');
      }
  }, [plan]);

  const handleDocumentationChange = useCallback((field: keyof Documentation, value: string) => {
    setDocumentation(prev => ({ ...prev, [field]: value }));
  }, []);

  const handleGeneratePlan = useCallback(async () => {
    if (tierDetails.weaverPlans !== 'unlimited' && usage.weaverPlans >= tierDetails.weaverPlans) {
        setError("You have reached your monthly limit for Weaver plans. Please upgrade your subscription.");
        audioService.playSound('error');
        return;
    }
    if (!goal.trim() || isLoading) return;

    setIsLoading(true);
    setError(null);
    setPlan(null);
    setNewlyGenerated(false);
    audioService.playSound('send');

    try {
      const generatedPlan = await generateDevelopmentPlan(goal, documentation.geminiContext);
      setPlan(generatedPlan);
      setNewlyGenerated(true);
      incrementUsage('weaverPlans');
      audioService.playSound('receive');

      telemetryService?.recordEvent({
        eventType: 'ai_response',
        interactionType: 'generate_dev_plan',
        tab: 'Weaver',
        userInput: goal,
        aiOutput: JSON.stringify(generatedPlan.implementationTasks.map(t => t.description)),
        outcome: 'success',
        tokenUsage: generatedPlan.tokenUsage,
        modelUsed: 'gemini-2.5-pro'
      });

      versionControlService?.captureVersion(
        'development_plan',
        `weaver_plan_${Date.now()}`,
        JSON.stringify(generatedPlan, null, 2),
        'ai_response',
        `Generated plan for goal: ${goal.substring(0, 50)}...`
      );

    } catch (e: any) {
      const userFriendlyMessage = parseApiError(e);
      setError(userFriendlyMessage);
      audioService.playSound('error');
      telemetryService?.recordEvent({
        eventType: 'ai_response',
        interactionType: 'generate_dev_plan',
        tab: 'Weaver',
        userInput: goal,
        outcome: 'error',
        customData: { error: userFriendlyMessage }
      });
    } finally {
      setIsLoading(false);
    }
  }, [goal, isLoading, documentation.geminiContext, telemetryService, versionControlService, usage, tierDetails, incrementUsage]);

  useEffect(() => {
    if (newlyGenerated) {
      const timer = setTimeout(() => setNewlyGenerated(false), 1000);
      return () => clearTimeout(timer);
    }
  }, [newlyGenerated]);

  const plansUsed = usage.weaverPlans;
  const planLimit = tierDetails.weaverPlans;
  const isLimitReached = planLimit !== 'unlimited' && plansUsed >= planLimit;

  return (
    <div className="flex flex-col h-full p-4 md:p-6 gap-6">
      {/* Top Bar for Goal Input */}
      <div className="flex-shrink-0 bg-gray-800/50 border border-gray-700/50 rounded-lg p-4 shadow-lg">
        <div className="flex flex-col gap-4">
          <div className="flex flex-col md:flex-row items-center gap-4">
            <textarea
                value={goal}
                onChange={(e) => setGoal(e.target.value)}
                placeholder="Enter your high-level development goal here..."
                className="w-full flex-grow bg-gray-900/50 rounded-md border border-gray-700 p-3 text-gray-300 placeholder-gray-500 resize-none focus:outline-none focus:ring-2 focus:ring-fuchsia-500"
                rows={2}
                disabled={isLoading || isLimitReached}
            />
            <button
                onClick={handleGeneratePlan}
                disabled={isLoading || !goal.trim() || isLimitReached}
                className="w-full md:w-auto flex-shrink-0 px-6 py-3 bg-fuchsia-600 text-white font-semibold rounded-md hover:bg-fuchsia-500 disabled:bg-gray-700 disabled:cursor-not-allowed transition-colors flex items-center justify-center gap-2"
            >
                {isLoading ? <Loader /> : <SparklesIcon className="w-5 h-5" />}
                {isLoading ? 'Generating...' : 'Generate Plan'}
            </button>
          </div>
          <RealTimeFeedback 
             isLoading={isRTLoading} 
             feedback={feedback} 
             onApply={applyFeedback} 
             onDiscard={discardFeedback} 
          />
        </div>
        <div className="mt-2 text-right text-xs text-gray-400">
          Plans Used: {plansUsed} / {planLimit === 'unlimited' ? 'Unlimited' : planLimit}
        </div>
        {error && (
            <div className="mt-3 p-3 bg-red-900/50 border border-red-700/50 rounded-md text-sm text-red-300 flex items-center justify-between">
                <span>{error}</span>
                <button onClick={() => setError(null)} className="text-red-200 hover:text-white">
                    <XMarkIcon className="w-5 h-5" />
                </button>
            </div>
        )}
      </div>

      {/* Main Content Area */}
      <div className="flex-grow grid grid-cols-1 lg:grid-cols-2 gap-6 overflow-hidden relative">
        {/* Left Panel: Toggleable Memory vs Engine */}
        <div className="h-full flex flex-col overflow-hidden relative group">
            {/* Toggle Switch */}
            <div className="absolute top-2 right-2 z-20 flex gap-2 bg-gray-900/80 p-1 rounded-lg border border-gray-700 backdrop-blur-sm opacity-0 group-hover:opacity-100 transition-opacity">
                <button 
                    onClick={() => setLeftPanelMode('memory')}
                    className={`p-1.5 rounded transition-colors ${leftPanelMode === 'memory' ? 'bg-gray-700 text-white' : 'text-gray-400 hover:text-white'}`}
                    title="Project Memory"
                >
                    <BookIcon className="w-4 h-4" />
                </button>
                <button 
                    onClick={() => setLeftPanelMode('engine')}
                    className={`p-1.5 rounded transition-colors ${leftPanelMode === 'engine' ? 'bg-fuchsia-600 text-white' : 'text-gray-400 hover:text-fuchsia-400'}`}
                    title="Capability Engine"
                >
                    <BoltIcon className="w-4 h-4" />
                </button>
            </div>

            {leftPanelMode === 'memory' ? (
                <MemoryPanel documentation={documentation} onDocumentationChange={handleDocumentationChange} />
            ) : (
                <FixEngine fixes={fixes} onUpdateFixes={setFixes} />
            )}
        </div>

        {/* Right Panel: Plan Display */}
        <div className="h-full overflow-hidden">
            <PlanDisplay plan={plan} newlyGenerated={newlyGenerated} />
        </div>
      </div>
    </div>
  );
};

export default Weaver;
